11	@Observable
12	final class NavigationManager {
13	    
14	    var isActiveAnalysisPresented: Bool = false
15	    var path = NavigationPath()
16	    
17	    @MainActor
18	    func push(to route: AppRoute) {
19	        path.append(route)
20	    }
21	    
22	    func reset(to route: AppRoute) {
23	        Task { @MainActor [weak self] in
24	            guard let self else { return }
25	            await UIApplication.rootViewController?.dismissAsync(animated: true)
26	            self.path = NavigationPath()
27	            self.path.append(route)
28	        }
29	    }
30	}
31	
