8	import SwiftUI
9	import GoogleMaps
10	import FactoryKit
11	import Siren
12	
13	@main
14	struct AppView: SwiftUI.App {
15	
16	    @InjectedObservable(\.migration) private var migration
17	    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
18	    @Injected(\.databaseMigrationManager) private var databaseMigrationManager
19	    
20	    var body: some Scene {
21	        WindowGroup {
22	            Group {
23	                switch migration.state {
24	                case .launching:
25	                    LaunchScreen()
26	                case .migrating:
27	                    MigrationView()
28	                case .failure(let databaseURL):
29	                    MigrationErrorView(databaseURL: databaseURL)
30	                case .ready:
31	                    MainContentView()
32	                }
33	            }
34	            .animation(.easeInOut(duration: 0.3), value: migration.state)
35	            .onAppear {
36	                guard UIApplication.shared.isProtectedDataAvailable else { return }
37	                prepareDatabase()
38	            }
39	            .onReceive(NotificationCenter.default.publisher(for: UIApplication.protectedDataDidBecomeAvailableNotification)) { _ in
40	                prepareDatabase()
41	            }
42	        }
43	    }
44	    
45	    private func prepareDatabase() {
46	        guard migration.state == .launching else { return }
47	        _ = Container.shared.backgroundDatabase()
48	        Task {
49	            await databaseMigrationManager.migrateDatabaseIfNeeded()
50	        }
51	    }
52	}
