8	import Foundation
9	import CoreBluetooth
10	
11	/// Найденное устройство для подключения
12	struct RadiaCode: Hashable {
13	    
14	    static let hostID: UInt32 = 0xFF12FF01
15	    
16	    let device: Device
17	    let signal: BluetoothSignal
18	    let connection: CBPeripheral
19	    
20	    static func == (lhs: RadiaCode, rhs: RadiaCode) -> Bool {
21	        lhs.device == rhs.device
22	    }
23	    
24	    func hash(into hasher: inout Hasher) {
25	         hasher.combine(device)
26	     }
27	}
28	
29	extension RadiaCode {
30	    
31	    struct Device: Hashable {
32	        
33	        let identifier: String
34	        let model: Model
35	        
36	        init(identifier: String, model: String) {
37	            self.identifier = identifier
38	            self.model = Model(rawValue: model)
39	        }
40	        
41	        init?(serialNumber: String) {
42	            let parts = serialNumber.split(separator: "-", omittingEmptySubsequences: false).map(String.init)
43	            guard parts.count >= 3, parts[0] == "RC" else { return nil }
44	            self.identifier = serialNumber
45	            self.model = Model(serialCode: parts[1])
46	        }
47	        
48	        static func == (lhs: Device, rhs: Device) -> Bool {
49	            lhs.identifier == rhs.identifier
50	        }
51	    }
52	}
