54	extension RadiaCode {
55	 
56	    enum Family {
57	        case radiaCode10x
58	        case radiaCode11x
59	        case radiaCode103G
60	        case radiaCode41x
61	        
62	        var postFix: String {
63	            switch self {
64	            case .radiaCode10x: return "_10x"
65	            case .radiaCode11x: return "_11x"
66	            case .radiaCode103G: return "_103G"
67	            case .radiaCode41x: return "_41x"
68	            }
69	        }
70	    }
71	    
72	    /// Модели устройств RadiaCode
73	    enum Model: Hashable {
74	
75	        static let defaultName = "RadiaCode"
76	
77	        case radiacode101
78	        case radiacode102
79	        case radiacode103
80	        case radiacode103G
81	        case radiacode110
82	        case radiacodeZero
83	        case radiacode(String)
84	        
85	        typealias RawValue = String
86	
87	        init(rawValue: String) {
88	            switch rawValue {
89	            case "RadiaCode-101": self = .radiacode101
90	            case "RadiaCode-102": self = .radiacode102
91	            case "RadiaCode-103": self = .radiacode103
92	            case "RadiaCode-103G": self = .radiacode103G
93	            case "RadiaCode-110": self = .radiacode110
94	            case "RadiaCode Zero": self = .radiacodeZero
95	            default: self = .radiacode(rawValue)
96	            }
97	        }
98	        
99	        init(serialCode: String) {
100	            switch serialCode {
101	            case "101": self = .radiacode101
102	            case "102": self = .radiacode102
103	            case "103": self = .radiacode103
104	            case "103G": self = .radiacode103G
105	            case "110": self = .radiacode110
106	            case "Zero", "410": self = .radiacodeZero
107	            default: self = .radiacode("RadiaCode-\(serialCode)")
108	            }
109	        }
110	        
111	        var family: Family {
112	            switch self {
113	            case .radiacode101, .radiacode102, .radiacode103:
114	                return .radiaCode10x
115	            case .radiacode103G:
116	                return .radiaCode103G
117	            case .radiacode110:
118	                return .radiaCode11x
119	            case .radiacodeZero:
120	                return .radiaCode41x
121	            case .radiacode(let name):
122	                if name.hasPrefix("RadiaCode-10") {
123	                    return .radiaCode10x
124	                } else if name.hasPrefix("RadiaCode-11") {
125	                    return .radiaCode11x
126	                } else if name.hasPrefix("RadiaCode-41") {
127	                    return .radiaCode41x
128	                } else {
129	                    return .radiaCode10x
130	                }
131	            }
132	        }
133	                
134	        var name: String {
135	            switch self {
136	            case .radiacode101: "RadiaCode-101"
137	            case .radiacode102: "RadiaCode-102"
138	            case .radiacode103: "RadiaCode-103"
139	            case .radiacode103G: "RadiaCode-103G"
140	            case .radiacode110: "RadiaCode-110"
141	            case .radiacodeZero: "RadiaCode-Zero"
142	            case .radiacode(let name): name
143	            }
144	        }
145	    }
146	}
